functions._selectOrCreateActor:
function _selectOrCreateActor(uint256 seed) internal returns (address actor) {
    if (actors.length == 0 || seed % 3 == 0) {
        actor = makeAddr(string(abi.encodePacked("actor", seed)));
    } else {
        actor = actors[seed % actors.length];
    }
}

functions.actorsLength:
function actorsLength() external view returns (uint256) {
    return actors.length;
}

functions.handler_deposit:
function handler_deposit(uint256 amount, uint256 actorSeed) external {
    address actor = _selectOrCreateActor(actorSeed);
    if (!_isActor[actor]) {
        _isActor[actor] = true;
        actors.push(actor);
    }
    uint256 remaining = vault.depositCap() - vault.totalAssets();
    if (remaining == 0) return;
    amount = bound(amount, 1, remaining);
    deal(address(token), actor, token.balanceOf(actor) + amount);
    vm.startPrank(actor);
    token.approve(address(vault), amount);
    vault.deposit(amount);
    vm.stopPrank();
    ghost_total_deposited += amount;
    ghost_user_deposited[actor] += amount;
}

functions.handler_withdraw:
function handler_withdraw(uint256 shares, uint256 actorSeed) external {
    if (actors.length == 0) return;
    address actor = actors[actorSeed % actors.length];
    uint256 userShares = vault.balanceOf(actor);
    if (userShares == 0) return;
    shares = bound(shares, 1, userShares);
    vm.prank(actor);
    vault.withdraw(shares);
    ghost_total_withdrawn += shares;
    ghost_user_withdrawn[actor] += shares;
}

invariants.invariant_deposit_cap_not_exceeded:
function invariant_deposit_cap_not_exceeded() external view {
    assertLe(
        vault.totalAssets(),
        vault.depositCap(),
        "totalAssets exceeds depositCap"
    );
}

invariants.invariant_per_user_balance_equals_ghost:
function invariant_per_user_balance_equals_ghost() external view {
    uint256 len = handler.actorsLength();
    for (uint256 i = 0; i < len; i++) {
        address actor = handler.actors(i);
        assertEq(
            vault.balanceOf(actor),
            handler.ghost_user_deposited(actor) - handler.ghost_user_withdrawn(actor),
            "balanceOf(actor) != ghost_user_deposited - ghost_user_withdrawn"
        );
    }
}

invariants.invariant_token_solvency:
function invariant_token_solvency() external view {
    assertGe(
        vault.token().balanceOf(address(vault)),
        vault.totalAssets(),
        "vault token balance < totalAssets"
    );
}

invariants.invariant_totalAssets_equals_ghost:
function invariant_totalAssets_equals_ghost() external view {
    assertEq(
        vault.totalAssets(),
        handler.ghost_total_deposited() - handler.ghost_total_withdrawn(),
        "totalAssets != ghost_total_deposited - ghost_total_withdrawn"
    );
}

invariants.invariant_totalAssets_equals_sum_of_bala:
function invariant_totalAssets_equals_sum_of_balances() external view {
    uint256 len = handler.actorsLength();
    uint256 sumBalances = 0;
    for (uint256 i = 0; i < len; i++) {
        address actor = handler.actors(i);
        sumBalances += vault.balanceOf(actor);
    }
    assertEq(
        vault.totalAssets(),
        sumBalances,
        "totalAssets != sum of all actor balances"
    );
}

invariants.invariant_user_withdrawn_le_deposited:
function invariant_user_withdrawn_le_deposited() external view {
    uint256 len = handler.actorsLength();
    for (uint256 i = 0; i < len; i++) {
        address actor = handler.actors(i);
        assertLe(
            handler.ghost_user_withdrawn(actor),
            handler.ghost_user_deposited(actor),
            "ghost_user_withdrawn > ghost_user_deposited for actor"
        );
    }
}
